   "emo_text": "Explanatory and pragmatic",
   "emo_alpha": 0.6,
   "source_segment_ids": ["seg_00015"]
 },
 {
   "speaker": "SPEAKER_00",
   "text": "Why is goal setting important?",
   "emo_text": "Curious and focused",
   "emo_alpha": 0.6,
   "source_segment_ids": ["seg_00050"]
 },
 {
   "speaker": "SPEAKER_02",
   "text": "Goals align our behavior and motivate us. We're neurologically wired for progress, and achieving small wins builds confidence.",
   "emo_text": "Insightful and encouraging",
   "emo_alpha": 0.6,
   "source_segment_ids": ["seg_00051"]
 },
 {
   "speaker": "SPEAKER_01",
   "text": "What is financial risk tolerance?",
   "emo_text": "Inquisitive and practical",
   "emo_alpha": 0.6,
   "source_segment_ids": ["seg_00058"]
 },
 {
   "speaker": "SPEAKER_02",
   "text": "Risk tolerance is our emotional-behavioral response to uncertainty—our willingness to endure volatility for potential long-term gain.",
   "emo_text": "Clear and explanatory",
   "emo_alpha": 0.6,
   "source_segment_ids": ["seg_00059"]
 },
 {
   "speaker": "SPEAKER_00",
   "text": "How does MRI help people make better financial decisions?",
   "emo_text": "Curious and forward-looking",
   "emo_alpha": 0.6,
   "source_segment_ids": ["seg_00080"]
 },
 {
   "speaker": "SPEAKER_02",
   "text": "MRI combines psychometric assessment with behavioral psychology for a holistic view, helping individuals understand themselves better to align behaviors with goals.",
   "emo_text": "Expert and informative",
   "emo_alpha": 0.6,
   "source_segment_ids": ["seg_00081"]
 },
 {
   "speaker": "SPEAKER_01",
   "text": "How do you define success?",
   "emo_text": "Reflective and personal",
   "emo_alpha": 0.6,
   "source_segment_ids": ["seg_00082"]
 },
 {
   "speaker": "SPEAKER_02",
   "text": "Success means alignment—of environment, behaviors, and people with what matters. Money is a tool to get there.",
   "emo_text": "Philosophical and heartfelt",
   "emo_alpha": 0.6,
   "source_segment_ids": ["seg_00083"]
 }
 ]
}"}

